// buildChunkClusters fetches chunk IDs, checks fingerprint cache, builds co-occurrence pairs,
// calls clusterEntities, converts labels, and bulk-inserts new cluster rows.
func buildChunkClusters(conn DBConn, namespace, algorithm string, minChunks int, force bool) (map[string]int, error) {
	rows, err := conn.Execute(
		"SELECT DISTINCT chunk_id FROM chunk_entities WHERE COALESCE(namespace, 'global') = ?",
		namespace,
	)
	if err != nil {
		return nil, fmt.Errorf("buildChunkClusters query: %w", err)
	}
	var chunkIDs []string
	for _, r := range rows {
		chunkIDs = append(chunkIDs, r[0])
	}

	if len(chunkIDs) < minChunks {
		return map[string]int{}, nil
	}

	fingerprint := chunkFingerprint(chunkIDs)

	if !force {
		cacheRows, err := conn.Execute(
			"SELECT chunk_fingerprint FROM context_graph_cache WHERE COALESCE(namespace, 'global') = ?",
			namespace,
		)
		if err == nil && len(cacheRows) > 0 && cacheRows[0][0] == fingerprint {
			existingRows, err2 := conn.Execute(
				"SELECT chunk_id, cluster_id FROM chunk_clusters WHERE COALESCE(namespace, 'global') = ?",
				namespace,
			)
			if err2 == nil && len(existingRows) > 0 {
				cached := make(map[string]int, len(existingRows))
				for _, r := range existingRows {
					cid := r[0]
					clusterID, _ := strconv.Atoi(r[1])
					cached[cid] = clusterID
				}
				return cached, nil
			}
		}
	}

	ceRows, err := conn.Execute(
		"SELECT chunk_id, entity_id FROM chunk_entities WHERE COALESCE(namespace, 'global') = ?",
		namespace,
	)
	if err != nil {
		return nil, fmt.Errorf("buildChunkClusters ce query: %w", err)
	}
	chunkToEntities := make(map[string][]string)
	for _, r := range ceRows {
		chunkID, entityID := r[0], r[1]
		chunkToEntities[chunkID] = append(chunkToEntities[chunkID], entityID)
	}

	entityToChunks := make(map[string][]string)
	for chunkID, entityIDs := range chunkToEntities {
		for _, eid := range entityIDs {
			entityToChunks[eid] = append(entityToChunks[eid], chunkID)
		}
	}

	type pairKey struct{ a, b string }
	cooccurrence := make(map[pairKey]float64)
	for _, chunks := range entityToChunks {
		for i := 0; i < len(chunks); i++ {
			for j := i + 1; j < len(chunks); j++ {
				a, b := chunks[i], chunks[j]
				if a > b {
					a, b = b, a
				}
				cooccurrence[pairKey{a, b}] += 1.0
			}
		}
	}

	coocMap := make(map[[2]string]float64, len(cooccurrence))
	for k, v := range cooccurrence {
		coocMap[[2]string{k.a, k.b}] = v
	}
	clusterMap, err := clusterEntities(coocMap, chunkIDs, algorithm)
	if err != nil {
		return nil, fmt.Errorf("clusterEntities: %w", err)
	}

	result := make(map[string]int, len(clusterMap))
	for chunkID, label := range clusterMap {
		num := strings.TrimPrefix(label, "cluster_")
		val, _ := strconv.Atoi(num)
		result[chunkID] = val
	}

	if _, err := conn.Execute("DELETE FROM chunk_clusters WHERE namespace = ?", namespace); err != nil {
		return nil, fmt.Errorf("delete chunk_clusters: %w", err)
	}
	if len(result) > 0 {
		var insertRows [][]interface{}
		for cid, cidInt := range result {
			insertRows = append(insertRows, []interface{}{cid, cidInt, namespace})
		}
		if err := conn.ExecuteMany(
			"INSERT INTO chunk_clusters (chunk_id, cluster_id, namespace) VALUES (?, ?, ?)",
			insertRows,
		); err != nil {
			return nil, fmt.Errorf("insert chunk_clusters: %w", err)
		}
	}

	return result, nil
}

