// Wait blocks until the running build finishes or the optional timeout elapses.
// Pass nil timeout to block indefinitely.
// Returns true if build is done (or never started), false if timed out.
func (b *RelationshipIndexBuilder) Wait(timeout *time.Duration) bool {
	if b.thread == nil {
		return true
	}
	var done chan struct{}
	go func() {
		b.thread.Wait()
		close(done)
	}()
	if timeout == nil {
		<-done
		return true
	}
	select {
	case <-done:
		return true
	case <-time.After(*timeout):
		return false
	}
}

