// GetContextGraphEdges returns edges from context_graph_edges for the given entity.
// Returns an empty slice if the context graph has not been built for the namespace.
func GetContextGraphEdges(conn DBConn, entityID, namespace string, minWeight float64) ([]ContextEdge, error) {
	hasEdgesRows, err := conn.Execute(
		"SELECT 1 FROM context_graph_edges WHERE namespace = ? LIMIT 1",
		namespace,
	)
	if err != nil || len(hasEdgesRows) == 0 {
		logger.Printf("DEBUG: context graph not built for namespace %q — skipping expansion; call build_context_graph() to enable", namespace)
		return []ContextEdge{}, nil
	}

	rows, err := conn.Execute(`
		SELECT target_entity_id, weight, svo_signal, cooccur_signal, cluster_signal
		FROM context_graph_edges
		WHERE source_entity_id = ? AND namespace = ? AND weight >= ?
		ORDER BY weight DESC`,
		entityID, namespace, minWeight,
	)
	if err != nil {
		return nil, fmt.Errorf("GetContextGraphEdges query: %w", err)
	}

	edges := make([]ContextEdge, 0, len(rows))
	for _, r := range rows {
		weight, _ := strconv.ParseFloat(r[1], 64)
		svoSignal, _ := strconv.ParseFloat(r[2], 64)
		cooccurSignal, _ := strconv.ParseFloat(r[3], 64)
		clusterSignal, _ := strconv.ParseFloat(r[4], 64)
		edges = append(edges, ContextEdge{
			SourceEntityID: entityID,
			TargetEntityID: r[0],
			Weight:         weight,
			SVOSignal:      svoSignal,
			CooccurSignal:  cooccurSignal,
			ClusterSignal:  clusterSignal,
		})
	}
	return edges, nil
}

