func BuildContextGraphAllNamespaces(
	conn DBConn,
	minWeight float64,
	force bool,
	algorithm string,
	minChunks int,
) (map[string]ContextGraphStats, error) {
	rows, err := conn.Execute("SELECT DISTINCT COALESCE(namespace, 'global') FROM chunk_entities")
	if err != nil {
		return nil, fmt.Errorf("BuildContextGraphAllNamespaces namespace query: %w", err)
	}

