// normalizeFinalEdges normalizes raw edge weights to [0,1] and filters by minWeight.
func normalizeFinalEdges(rawEdges []RawEdge, minWeight float64) []FinalEdge {
	if len(rawEdges) == 0 {
		return nil
	}

	maxRaw := 0.0
	for _, e := range rawEdges {
		if e.RawWeight > maxRaw {
			maxRaw = e.RawWeight
		}
	}

	var finalEdges []FinalEdge
	for _, e := range rawEdges {
		var weight float64
		if maxRaw > 0 {
			weight = e.RawWeight / maxRaw
		}
		if weight >= minWeight {
			finalEdges = append(finalEdges, FinalEdge{
				A:             e.A,
				B:             e.B,
				Weight:        weight,
				SVOSignal:     e.SVOSignal,
				CooccurSignal: e.CooccurSignal,
				ClusterSignal: e.ClusterSignal,
			})
		}
	}
	return finalEdges
}

// embedEntities builds entity text representations, encodes them with the embed model,
// deletes old entity embeddings, and writes the new ones.
func (p *EntityGraphPipeline) embedEntities(store Store, prog ProgressFn) (int, error) {
	if p.embedModel == nil {
		return 0, fmt.Errorf("embedEntities called without embedModel")
	}
	conn := store.DB().Conn()

	entityRows, err := conn.Execute(`
		SELECT e.id, e.name,
		       COALESCE(e.description, '') AS description,
		       e.entity_type
		FROM entities e`)
	if err != nil {
		return 0, fmt.Errorf("embedEntities entity query: %w", err)
	}

	if len(entityRows) == 0 {
		return 0, nil
	}

	aliasRows, err := conn.Execute(
		"SELECT entity_id, alias FROM entity_aliases WHERE namespace = ?",
		p.namespace,
	)
	if err != nil {
		aliasRows = nil
	}

	aliasesMap := make(map[string][]string)
	for _, r := range aliasRows {
		eid, alias := r[0], r[1]
		aliasesMap[eid] = append(aliasesMap[eid], alias)
	}

	var texts []string
	var chunks []DocumentChunk
	for _, r := range entityRows {
		entityID, name, description := r[0], r[1], r[2]
		parts := []string{name}
		if aliasList, ok := aliasesMap[entityID]; ok && len(aliasList) > 0 {
			parts = append(parts, strings.Join(aliasList, ", "))
		}
		if len(description) > 0 {
			parts = append(parts, description)
		}
		text := strings.Join(parts, ". ")
		texts = append(texts, text)
		chunks = append(chunks, DocumentChunk{
			DocumentName: fmt.Sprintf("__entity__%s", entityID),
			Content:      text,
			ChunkIndex:   0,
			ChunkType:    "entity",
		})
	}

	prog(PhaseEmbedEntities, 0, len(chunks))
	vecs, err := p.embedModel.Encode(texts)
	if err != nil {
		return 0, fmt.Errorf("embedEntities encode: %w", err)
	}

	if _, err := conn.Execute("DELETE FROM embeddings WHERE chunk_type = 'entity'"); err != nil {
		return 0, fmt.Errorf("embedEntities delete: %w", err)
	}
	if err := store.AddDocument(chunks, vecs); err != nil {
		return 0, fmt.Errorf("embedEntities AddDocument: %w", err)
	}
	prog(PhaseEmbedEntities, len(chunks), len(chunks))
	return len(chunks), nil
}

