func (p *EntityGraphPipeline) extractionPhase(
	eligible [][2]string,
	chunkEntitiesMap map[string][]EntityInfo,
	prog func(string, int, int),
) (*RelationshipIndex, map[string]string, map[string][]string, int, error) {
	relationshipIndex := NewRelationshipIndex()
	newDescriptions := make(map[string]string)
	newAliases := make(map[string][]string)
	chunksProcessed := 0

	total := len(eligible)
	prog(PhaseExtract, 0, total)

	type result struct {
		triples []*SVOTriple
		descs   map[string]string
		aliases map[string][]string
		err     error
	}

	resultsCh := make(chan result, total)
	sem := make(chan struct{}, p.concurrency)
	var wg sync.WaitGroup

	for _, row := range eligible {
		row := row
		wg.Add(1)
		go func() {
			defer wg.Done()
			sem <- struct{}{}
			defer func() { <-sem }()
			chunkID, content := row[0], row[1]
			entities := chunkEntitiesMap[chunkID]
			if len(entities) < 2 {
				resultsCh <- result{}
				return
			}
			triples, descs, aliases, _, err := p.extractor.ExtractEntityAnchored(content, chunkID, entities)
			resultsCh <- result{triples: triples, descs: descs, aliases: aliases, err: err}
		}()
	}

	go func() {
		wg.Wait()
		close(resultsCh)
	}()

	done := 0
	var firstErr error
	for res := range resultsCh {
		if res.err != nil && firstErr == nil {
			firstErr = res.err
		}
		for _, t := range res.triples {
			relationshipIndex.Add(t)
		}
		for k, v := range res.descs {
			newDescriptions[k] = v
		}
		for eid, aliasList := range res.aliases {
			newAliases[eid] = append(newAliases[eid], aliasList...)
		}
		done++
		chunksProcessed++
		prog(PhaseExtract, done, total)
	}

	if firstErr != nil {
		return nil, nil, nil, chunksProcessed, fmt.Errorf("extractionPhase: %w", firstErr)
	}
	return relationshipIndex, newDescriptions, newAliases, chunksProcessed, nil
}
